override fun onFailure(call: Call, e: IOException) {
    val cm = context.getSystemService(Context.CONNECTIVITY_SERVICE) as android.net.ConnectivityManager
    val capabilities = cm.getNetworkCapabilities(cm.activeNetwork)
    val isInternetUp = capabilities?.hasCapability(android.net.NetworkCapabilities.NET_CAPABILITY_INTERNET) == true

    val reason = when {
        !isInternetUp -> "Network unavailable. Check airplane mode or data connection."
        e is java.net.UnknownHostException -> "DNS failure. Check if your data plan has expired."
        e is java.net.SocketTimeoutException -> "Connection timed out. Signal might be too weak."
        e is java.net.ConnectException -> "Server unreachable. Check firewall or server status."
        else -> "Upload failed due to a transmission error."
    }

    DebugLogger.log("UPLOAD_ERR", "$reason (${e.message})")
    notifyVoice(context, reason, true)
    processNext(context)
}
override fun onResponse(call: Call, response: Response) {
    val contentType = response.header("Content-Type") ?: ""
    val bodyStr = response.body?.string() ?: ""

    if (response.isSuccessful && contentType.contains("application/json")) {
        val id = JSONObject(bodyStr).optString("id")
        if (id.isNotEmpty()) {
            DebugLogger.log("POLL", "ID: $id. Analyzing...")
            notifyVoice(context, "Upload success. Analyzing.")
            startPolling(context, id)
        } else {
            notifyVoice(context, "Server returned empty response.")
            processNext(context)
        }
    } else {
        val statusReason = when (response.code) {
            413 -> "Image file is too large for the server."
            429 -> "Too many requests. System is rate limited."
            403, 401 -> "Authentication expired. System update required."
            502, 503, 504 -> "Cloud server is currently under maintenance."
            else -> if (contentType.contains("text/html")) "Low balance or ISP redirection detected." 
                    else "Server error code ${response.code}"
        }
        DebugLogger.log("UPLOAD_ERR", "HTTP ${response.code}: $statusReason")
        notifyVoice(context, statusReason, true)
        processNext(context)
    }
    response.close()
}

